import{_ as a,c as i,o as t,ae as o}from"./chunks/framework.Bw7rlmih.js";const p=JSON.parse('{"title":"CP-002: Authentication and Authorization","description":"","frontmatter":{},"headers":[],"relativePath":"control-plane/atomic/CP-002-authn-authz.md","filePath":"control-plane/atomic/CP-002-authn-authz.md"}'),n={name:"control-plane/atomic/CP-002-authn-authz.md"};function l(c,e,r,s,d,u){return t(),i("div",null,e[0]||(e[0]=[o('<h1 id="cp-002-authentication-and-authorization" tabindex="-1">CP-002: Authentication and Authorization <a class="header-anchor" href="#cp-002-authentication-and-authorization" aria-label="Permalink to &quot;CP-002: Authentication and Authorization&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Define login and access control for humans, CI/CD, and services.</p><h2 id="inputs-outputs" tabindex="-1">Inputs / Outputs <a class="header-anchor" href="#inputs-outputs" aria-label="Permalink to &quot;Inputs / Outputs&quot;">​</a></h2><ul><li>Input: OIDC assertions, service identity, requested scope/action.</li><li>Output: short-lived access token and authorization decision.</li></ul><h2 id="public-interfaces" tabindex="-1">Public Interfaces <a class="header-anchor" href="#public-interfaces" aria-label="Permalink to &quot;Public Interfaces&quot;">​</a></h2><ul><li><code>konfigo login</code> (browser/device)</li><li><code>POST /v1/auth/exchange-oidc</code></li><li><code>POST /v1/auth/token</code></li></ul><h2 id="data-contracts" tabindex="-1">Data Contracts <a class="header-anchor" href="#data-contracts" aria-label="Permalink to &quot;Data Contracts&quot;">​</a></h2><p>Token claims required:</p><ul><li><code>sub</code></li><li><code>aud</code></li><li><code>exp</code></li><li><code>scope_prefixes[]</code></li><li><code>actor_type</code> (<code>human|ci|service</code>)</li></ul><h2 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h2><ul><li>Username/password is disabled by default.</li><li>Human auth requires OIDC SSO.</li><li>CI/CD auth uses workload OIDC exchange.</li><li>Access tokens are short-lived (default 15m).</li></ul><h2 id="failure-modes" tabindex="-1">Failure Modes <a class="header-anchor" href="#failure-modes" aria-label="Permalink to &quot;Failure Modes&quot;">​</a></h2><ul><li><code>401 invalid_identity_token</code></li><li><code>403 action_not_allowed_for_scope</code></li><li><code>403 protected_scope_requires_approval</code></li></ul><h2 id="acceptance-criteria" tabindex="-1">Acceptance Criteria <a class="header-anchor" href="#acceptance-criteria" aria-label="Permalink to &quot;Acceptance Criteria&quot;">​</a></h2><ol><li>Human CLI login works via OIDC browser/device flow.</li><li>GitHub/GitLab OIDC token can be exchanged for scoped token.</li><li>Expired token denies all actions.</li><li>Audit includes actor claims and decision reason.</li></ol><h2 id="out-of-scope" tabindex="-1">Out of Scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of Scope&quot;">​</a></h2><ul><li>Legacy password auth.</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li>CP-001 scope model.</li></ul>',20)]))}const f=a(n,[["render",l]]);export{p as __pageData,f as default};
